#include<bits/stdc++.h>
using namespace std;
const long long inf=0x3f3f3f3f3f3f3f3f;
struct edge
{
    long long to,val,nxt,cost;
}e[200010];
struct node
{
    int v,e;
}pre[200010];
long long head[200010],tot=1,res;
long long n,m,s,t,d[200010],h[200010],now[200010];
bool vis[200010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
    add1(v,u,0,-c);
}
void spfa()
{
    memset(vis,0,sizeof(vis));
    memset(h,0x3f,sizeof(h));
    long long tmp=h[0];
    deque<long long> q;
    q.push_back(s);
    h[s]=0;
    while(!q.empty())
    {
        long long t=q.front();
        q.pop_front();
        vis[t]=false;
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,cost=e[i].cost;
            if(e[i].val&&h[v]>h[t]+cost)
            {
                h[v]=h[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    if(q.empty()||h[v]>h[q.front()])
                    {
                        q.push_back(v);
                    }
                    else
                    {
                        q.push_front(v);
                    }
                }
            }
        }
    }
}
bool dijkstra()
{
    priority_queue<pair<long long,long long>> q;
    q.push({0,s});
    memset(vis,0,sizeof(vis));
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    d[s]=0;
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to;
            long long val=e[i].cost+h[t]-h[v];
            if(e[i].val&&d[v]>d[t]+val)
            {
                d[v]=d[t]+val;
                pre[v].v=t;
                pre[v].e=i;
                if(!vis[v])
                {
                    q.push({-d[v],v});
                }
            }
        }
    }
    return d[::t]!=tmp;
}
long long dinic()
{
    long long ans=0;
    spfa();
    while(dijkstra())
    {
        for(long long i=1;i<=t;i++)
        {
            h[i]+=d[i];
        }
        long long min1=inf;
        for(long long i=t;i!=s;i=pre[i].v)
        {
            min1=min(min1,e[pre[i].e].val);
        }
        for(long long i=t;i!=s;i=pre[i].v)
        {
            e[pre[i].e].val-=min1;
            e[pre[i].e^1].val+=min1;
        }
        ans+=min1;
        res+=min1*h[t];
    }
    return ans;
}
long long sum[200010],c[200010];
int main()
{
    scanf("%lld%lld",&n,&m);
    s=0;
    t=n+2;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
        add(i,i+1,inf,0);
    }
    add(s,1,c[1],0);
    for(long long i=1;i<=m;i++)
    {
        long long x,y,z;
        scanf("%lld%lld%lld",&x,&y,&z);
        add(x,y+1,inf,-z);
    }
    for(long long i=2;i<=n;i++)
    {
        if(c[i]<c[i-1])
        {
            add(i,t,c[i-1]-c[i],0);
        }
        else if(c[i]>c[i-1])
        {
            add(s,i,c[i]-c[i-1],0);
        }
    }
    add(n+1,t,c[n],0);
    dinic();
    printf("%lld",-res);
    return 0;
}
